#include <stdio.h>
#include <math.h>
#define MOD 1000000007LL
int main(){
    int T;
    scanf("%d", &T);
    while (T--){
        int H;
        scanf("%d", &H);
        int N = (1<<H) - 1;
        long long V[N+2];
        for(int i=1;i<=N;i++) scanf("%lld", &V[i]);
        long long modVal[N+2];
        for(int i=N;i>=1;i--){
            if(i*2 > N){ // leaf
                modVal[i] = V[i] % MOD;
            }else{
                long long leftVal = (V[i] % MOD) * modVal[i*2] % MOD;
                long long rightVal = (V[i] % MOD) * modVal[i*2+1] % MOD;
                modVal[i] = (leftVal > rightVal) ? leftVal : rightVal;
            }
        }
        printf("%lld\n", modVal[1]);
    }
    return 0;
}

