            int H = Integer.parseInt(br.readLine());
            int N = (1 << H) - 1;
            long[] V = new long[N + 2];
            StringTokenizer st = new StringTokenizer(br.readLine());
            for (int i = 1; i <= N; i++) V[i] = Long.parseLong(st.nextToken());
            long[] mod = new long[N + 2];
            for (int i = N; i >= 1; i--) {
                if (i * 2 > N) { // leaf
                    mod[i] = V[i] % MOD;
                } else {
                    long leftVal = (V[i] % MOD) * mod[i*2] % MOD;
                    long rightVal = (V[i] % MOD) * mod[i*2+1] % MOD;
                    mod[i] = (leftVal > rightVal) ? leftVal : rightVal;
                }
            }
            System.out.println(mod[1]);
        }
    }
}

