  const mod = new Array(N + 2).fill(0n);
  for (let i = N; i >= 1; i--) {
    if (i * 2 > N) { // leaf
      mod[i] = V[i] % MOD;
    } else {
      const leftVal = (V[i] % MOD) * mod[i * 2] % MOD;
      const rightVal = (V[i] % MOD) * mod[i * 2 + 1] % MOD;
      mod[i] = (leftVal > rightVal) ? leftVal : rightVal;
